INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57f41407-moex-00093', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「1930年的〈南國〉是黃土水追求臺灣主題的巔峰之作。芭蕉葉子下，五隻水牛相互重疊，牛頭與腿 高高低低，產生漸變的節奏。從斗笠及水槽判斷，三名小孩看似臺灣農村兒童。作品雖然以臺灣為背 景，同時洋溢著南國樂園氣氛，除使用西方寫實雕塑手法，也展現出東方雕塑中的薄雕素養，可說是 巧妙融合了東西方雕塑技巧，將臺灣獨特的風景融入作品之中。」 根據上文，下列選項正確的是：', '["〈南國〉除展現臺灣農村主題，也描繪對南方樂園的想像", "黃土水利用五隻水牛的前後高低，營造出畫面的漸變節奏", "作者藉由芭蕉及斗笠樣式判斷，雕塑主題是臺灣農村兒童", "黃土水結合東西方雕塑技巧的手法，使作品充滿現代氣息 〈南國〉的技巧及主題，反映合併東西方藝術特點的企圖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00094', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「長期生活在臺灣的人，對兒童在公共場合的嬉鬧司空見慣，但臺灣兒童的這種行為模式並非舉世皆 然，也有許多人似乎認為，小孩就應該天真活潑，不必多加管束，等他們長大，自然就懂事了。兒童 在公共場合是否有遵守規範的習慣，與他們是否天真活潑沒有必然的關係，許多小孩在公共場合奔跑 叫嚷，也許可以算是活潑，但從表情來看，很難用天真來形容。」 下列選項何者符合上文的觀點？', '["天真活潑常被當成放任兒童行為的藉口", "教育兒童以強勢改變兒童的本性為重點", "兒童在公共場合的表現，應是普世性的", "兒童應有能力配合公共場合的行為規範 兒童教育需順應自然，尊重他們的天性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00095', 'judicial-57f41407', 'judicial-57f41407-moex-114-34c7f7f6', 'sub-judicial-57f41407-02', NULL, 'single_choice', '「在農村裡，大自然曾經幾乎完全操縱著人們的悲歡，陽光、風雨、氣候，甚至於土質仍是影響作物 生產的最大力量。在神祕不可解的年代中，對它的敬畏使人們傾向於泛神論。現在，人們雖還在心底 裡尊重大自然，一方面卻已在物質主義的驅使下，開始對它進行有形無形的改造工作了。農人膜拜祭 祀自然時所有的臣服與感恩意味逐漸淡了，祭拜的盛會也終將會慢慢式微成平淡生活中的興奮點綴。」 根據上文，下列選項敘述正確的是：', '["過去之所以傾向泛神論，是因那年代人們是無知的", "根植於傳統農業的節慶儀式，在現代已成平淡生活中的調劑", "現代人和過去一樣膜拜、祭祀自然，但對它不再臣服、感恩", "現代人雖還算尊重大自然，卻因物質主義興起，有意無意地改造大自然 大自然操縱著農村人們的悲歡，是因陽光、風雨、土質等影響作物生長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "16c911fc4062", "answer_pdf_sha1": "ac5dd4608ec6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00096', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於管轄之規定，下列敘述何者錯誤？', '["不動產之經界涉訟者，專屬不動產所在地之法院管轄", "定法院之管轄，以起訴時為準", "除專屬管轄外，被告不抗辯法院無管轄權，而為本案之言詞辯論者，以其法院為有管轄權之法院", "兩造得以合意排除專屬管轄法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00097', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '甲向福建金門地方法院（下稱金門地院）起訴主張伊持有乙簽發票面金額新臺幣 200 萬元之支票乙 紙，爰依票據法律關係，請求乙如數給付票款。第一審判決甲全部敗訴，甲不服提起上訴。嗣於第二 審程序中，甲主張審理本件訴訟之含兼任該院院長在內之合議庭3位法官有迴避之事由，聲請均應迴 避。而金門地院於本件法官迴避聲請時之法官人數，含兼任院長為5人。關於法官迴避，下列敘述何 者正確？', '["本件訴訟為本於票據有所請求而涉訟，適用簡易訴訟程序。關於本件法官迴避之聲請，由金門地院 法官1人獨任裁定", "因金門地院之法官不足法定人數，不能組成合議庭，由該院兼院長之法官裁定", "因金門地院之法官不足法定人數，不能組成合議庭，關於本件法官迴避之聲請，由直接上級法院即 最高法院裁定", "因金門地院之法官不足法定人數，不能組成合議庭，關於本件法官迴避之聲請，由直接上級法院即 福建高等法院金門分院裁定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00098', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者不是民事起訴狀之法定必要記載事項？', '["定法院管轄所必要之事項", "訴訟標的之原因事實", "無訴訟能力人之法定代理人", "應受判決事項之聲明"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00099', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟主體，下列敘述何者正確？', '["有權利能力者，有訴訟能力", "非法人團體只需委任訴訟代理人，即有當事人能力", "胎兒均無當事人能力", "對於無訴訟能力人為訴訟行為，因其無法定代理人，恐致久延而受損害者，得聲請受訴法院之審判 長為其選任特別代理人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00100', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於訴訟參加，下列敘述何者錯誤？', '["法院得逕依職權於訴訟繫屬中公告曉示使其他利害關係之第三人參加訴訟", "當事人得於訴訟繫屬中將訴訟告知利害關係之第三人使其參加訴訟", "就兩造之訴訟有法律上利害關係之第三人得參加訴訟", "利害關係人得參加而因可歸責於己之事由未參加訴訟，判決確定後即不得再提起第三人撤銷訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00101', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者，不屬民事訴訟法規定之訴訟費用？', '["證人之日費、旅費", "鑑定人報酬", "訴訟文書之影印費", "當事人自行委任第一審律師之酬金"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00102', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於不變期間，下列敘述何者正確？', '["當事人合意停止訴訟程序時，不變期間亦停止進行", "遲誤不變期間，僅得以回復原狀之程序為救濟", "遲誤不變期間已逾6個月者，不得聲請回復原狀", "法院送達於當事人之判決書誤寫為較短之上訴不變期間時，當事人須於該記載之不變期間內，提起 上訴始為合法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
